SELECT t.* FROM eb_user_memorial t
AND t.uid = #{query.uid}
AND t.pid = #{query.pid}
AND (t.title LIKE CONCAT('%', #{query.titleSearch}, '%') OR t.content LIKE CONCAT('%', #{query.titleSearch}, '%'))
ORDER BY t.updated_at DESC

SELECT t.*
FROM eb_user_memorial t

	t.uid = #{uid}
	AND DATE_FORMAT(t.updated_at, '%Y-%m') = #{ym}

		AND t.pid = #{pid}


		AND (t.title LIKE CONCAT('%', #{titleSearch}, '%')
		OR t.content LIKE CONCAT('%', #{titleSearch}, '%'))


ORDER BY t.updated_at DESC

SELECT ym FROM (
	SELECT DATE_FORMAT(t.updated_at, '%Y-%m') AS ym
	FROM eb_user_memorial t

		t.uid = #{uid}

			AND t.pid = #{pid}


			AND (t.title LIKE CONCAT('%', #{titleSearch}, '%')
			OR t.content LIKE CONCAT('%', #{titleSearch}, '%'))


	GROUP BY DATE_FORMAT(t.updated_at, '%Y-%m')
) g
ORDER BY ym DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM (
	SELECT 1
	FROM eb_user_memorial t

		t.uid = #{uid}

			AND t.pid = #{pid}


			AND (t.title LIKE CONCAT('%', #{titleSearch}, '%')
			OR t.content LIKE CONCAT('%', #{titleSearch}, '%'))


	GROUP BY DATE_FORMAT(t.updated_at, '%Y-%m')
) x
